UPDATE produits_complementaires SET phrase_conseil = sub.phrase
FROM (VALUES ('d241c159-afb6-43d2-a05f-3188c06a64ec'::uuid, 'L''irritation de la gorge peut survenir avec les allergies, le miel et la propolis adoucissent la muqueuse et forment un film protecteur.'),('d49e227a-3374-469c-ac0a-c86c4cd0616d'::uuid, 'L''allergie provoque un encombrement respiratoire, l''huile essentielle d''eucalyptus libère les voies nasales par son action expectorante.'),('bbc95eeb-a3e9-4e5b-8dd9-9beadb5570d3'::uuid, 'La rhinite allergique entraîne une inflammation nasale, l''eau de mer hypertonique aide à désencombrer et réduire l''œdème.'),('2e1af84f-b06d-4008-99fa-bf2180379f2a'::uuid, 'Les irritations de la gorge peuvent accompagner les allergies, le miel et la propolis adoucissent la muqueuse et forment un film protecteur.'),('7176fcda-453a-46e5-8e05-d74da15bda31'::uuid, 'L''allergie peut encombrer les voies respiratoires, l''huile essentielle d''eucalyptus aide à libérer le nez et la gorge.'),('5a4cb776-a608-440b-834b-05bed56c10ef'::uuid, 'Certains traitements peuvent fragiliser l''immunité, la vitamine D3 participe à la modulation de la réponse immunitaire.'),('59193471-335f-492c-9bf9-2818e106b9b8'::uuid, 'Les traitements peuvent affaiblir les défenses immunitaires, la vitamine D3 joue un rôle clé dans le soutien du système immunitaire.'),('6552b7ac-f9f6-4f85-9ad4-d19e1b6e8b2d'::uuid, 'Un manque de vitamine D peut impacter la vitalité générale, la vitamine D3 contribue à l''équilibre immunitaire et osseux.'),('1c9f4633-6ea5-48fa-b1b0-b2ef58d67232'::uuid, 'Les troubles cardiovasculaires nécessitent un soutien, les Oméga 3 contribuent à la régulation du rythme cardiaque et de la tension.'),('1a0e1aea-2873-4ec8-a650-825add11888d'::uuid, 'Le muscle cardiaque est énergivore, la Coenzyme Q10 est essentielle à la production d''énergie cellulaire pour sa bonne fonction.'),('4c735e7e-8abb-404f-b425-3a3804b1acf4'::uuid, 'La surveillance de la tension est primordiale, le tensiomètre permet de mesurer précisément la pression artérielle à domicile.'),('304a5c4e-725a-4d0f-8997-d9deddd0c658'::uuid, 'Les antibiotiques perturbent la flore intestinale, les probiotiques rétablissent l''équilibre microbien pour une digestion saine.'),('e21579b7-0bbd-4b0d-9dec-73521bf700a7'::uuid, 'Les infections fragilisent le système immunitaire, la vitamine C renforce les défenses pour une meilleure résistance aux agents pathogènes.'),('eca157cf-3734-444e-bd6c-699a4a0e1fe7'::uuid, 'Les irritations de la gorge peuvent accompagner une infection, la propolis forme un film protecteur et apaise les muqueuses.'),('08ad479e-cf07-4314-9ee2-6cc13b18858f'::uuid, 'La fatigue nerveuse peut amplifier les symptômes, le magnésium marin et la B6 contribuent à un fonctionnement normal du système nerveux.'),('996dbeff-01f7-466e-9113-2438533e0840'::uuid, 'Les troubles du sommeil affectent la récupération, la mélatonine régule le cycle veille-sommeil et facilite l''endormissement.'),('4d819fa1-b465-4593-8213-92628b01cacd'::uuid, 'Le stress peut perturber l''endormissement, la lavande aide à la détente et favorise un sommeil réparateur.'),('3d13168e-2925-42be-b1f0-96980d72488d'::uuid, 'Un soutien cardiovasculaire est important, les Oméga 3 contribuent à une fonction cardiaque et vasculaire optimale.'),('6523d5bb-8eed-496c-b33c-774ea8fd3432'::uuid, 'Le cœur a des besoins énergétiques élevés, la Coenzyme Q10 est essentielle à la production d''énergie cellulaire pour sa vigueur.'),('4445266a-80a0-42f8-9e1b-b5f18a87a3c9'::uuid, 'La prise d''anticoagulants implique une surveillance, le tensiomètre permet un suivi régulier de la pression artérielle.'),('d19aa363-2311-4f00-839f-d9c7e19cc2c4'::uuid, 'La fatigue émotionnelle peut accompagner les traitements, le magnésium marin et la B6 soutiennent les fonctions psychologiques normales.'),('86d32727-9143-40e7-8aae-310edcd98013'::uuid, 'Les troubles du sommeil peuvent affecter l''humeur, la mélatonine aide à réguler le cycle de sommeil pour un repos de qualité.'),('d5fe21b1-2267-4451-ac1f-46b97724dc9a'::uuid, 'Le stress et l''anxiété peuvent perturber le repos, la lavande favorise la détente nerveuse pour un sommeil paisible.'),('5e5cbd17-f116-4928-94d8-7665ee67bf6b'::uuid, 'La fatigue et le stress peuvent être accrus, le magnésium marin et la B6 contribuent au bon fonctionnement du système nerveux.'),('02ef73d4-0740-44f2-91cd-20e872abf59b'::uuid, 'Les difficultés d''endormissement impactent la qualité de vie, la mélatonine aide à réduire le temps nécessaire pour s''endormir.'),('31523a55-3b85-4de5-8636-447161977aff'::uuid, 'Le stress peut perturber le sommeil, la lavande aide à la relaxation et favorise un endormissement plus serein.'),('7bd31bce-c806-4b65-9399-3c3c7a6d7cf6'::uuid, 'La surveillance de la glycémie est essentielle, le lecteur FreeStyle permet un suivi précis de votre taux de sucre.'),('68d1a2a4-a49b-4c07-8a12-5511df20292b'::uuid, 'Le métabolisme des glucides est fondamental dans le diabète, le chrome et la cannelle participent à sa régulation.'),('8aa4cfad-9135-4275-a0df-9e1155fe1a87'::uuid, 'Les pieds diabétiques ont une peau fragile et sensible, la crème spécifique hydrate et protège l''intégrité cutanée.'),('33484bd6-982d-4e84-9087-4a6102b99a96'::uuid, 'Le système nerveux est sollicité lors de l''épilepsie, le magnésium marin et la B6 contribuent à son fonctionnement normal.')) AS sub(id, phrase)
WHERE produits_complementaires.id = sub.id;